<script setup>
import { ref, watch } from 'vue'
import { Close, Delete, Plus } from '@element-plus/icons-vue'

const props = defineProps({
  habit: {
    type: Object,
    default: null
  },
  visible: {
    type: Boolean,
    default: false
  }
})

const emit = defineEmits(['add', 'cancel', 'update:visible'])

const habitName = ref(props.habit?.name || '')
const description = ref(props.habit?.description || '')

// 监听habit变化，更新表单数据
watch(() => props.habit, (newHabit) => {
  if (newHabit) {
    habitName.value = newHabit.name || ''
    description.value = newHabit.description || ''
  } else {
    habitName.value = ''
    description.value = ''
  }
}, { immediate: true })

const submitForm = () => {
  if (!habitName.value.trim()) return
  
  const habitData = {
    name: habitName.value.trim(),
    description: description.value.trim(),
    frequency: props.habit?.frequency || 'daily',
    reminders: props.habit?.reminders || []
  }
  
  emit('add', habitData)
  emit('update:visible', false)
}

const handleCancel = () => {
  emit('cancel')
  emit('update:visible', false)
}
</script>

<template>
  <el-dialog
    :model-value="visible"
    @update:model-value="(value) => emit('update:visible', value)"
    :title="habit ? 'Edit Habit' : 'Add Habit'"
    width="500px"
    :close-on-click-modal="false"
    class="habit-form-dialog"
    @close="handleCancel"
  >
    <el-form
      label-width="80px"
      class="habit-form"
      @submit.prevent="submitForm"
    >
      <el-form-item label="Name" required>
        <el-input
          v-model="habitName"
          placeholder="e.g., Morning Exercise, Reading"
          clearable
        />
      </el-form-item>
      
      <el-form-item label="Description">
        <el-input
          v-model="description"
          placeholder="e.g., 每天早上6点起床锻炼30分钟"
          type="textarea"
          rows="3"
        />
      </el-form-item>
      
      <el-form-item>
        <div class="form-actions">
          <el-button type="default" @click="handleCancel" style="width: 160px; padding: 6px; font-size: 14px;">Cancel</el-button>
          <el-button native-type="submit" class="site-primary-button" style="width: 160px; padding: 6px; font-size: 14px;">Save</el-button>
        </div>
      </el-form-item>
    </el-form>
  </el-dialog>
</template>

